import React from 'react';
import { Link } from 'react-router-dom';

const SchoolHeader = () => {
    return (
        <div className="bg-gradient-to-r from-blue-900 via-blue-800 to-blue-900 text-white py-3 px-4 shadow-lg">
            <div className="max-w-7xl mx-auto">
                <div className="flex flex-col md:flex-row justify-between items-center text-center md:text-left">
                    {/* Logo & School Name */}
                    <div className="flex items-center gap-3 mb-2 md:mb-0">
                        {/* Uncomment if you have a logo */}
                        {/* <img 
                            src="/images/school-logo.png" 
                            alt="School Logo" 
                            className="h-12 w-12 object-contain"
                        /> */}
                        <div>
                            <h1 className="text-xl md:text-2xl font-bold tracking-wider flex items-center gap-2">
                                🏫 Podar International School, Latur
                            </h1>
                            <p className="text-sm md:text-base text-blue-200 font-medium">
                                Khadgoan Ring Road
                            </p>
                        </div>
                    </div>
                    
                    {/* Event Details */}
                    <div className="flex flex-col md:flex-row items-center gap-2 md:gap-6">
                        <div className="bg-gradient-to-r from-yellow-400 to-yellow-500 text-blue-900 px-4 py-1 rounded-full font-bold text-sm md:text-base shadow-lg">
                            ⚡ Spark 4.0
                        </div>
                        <div className="text-sm md:text-base text-blue-200 font-medium">
                            Science Fair 2026-27
                        </div>
                        <div className="hidden md:block text-blue-300 text-sm">
                            📅 2026-27
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default SchoolHeader;
